123	double calculate_variance_from_sums(double sum_sq_group_totals, double total_weight_double, int D_val) {
124	    if (D_val <= 0) return 1e18;
125	    double mean_weight = total_weight_double / D_val;
126	    double variance = sum_sq_group_totals / D_val - mean_weight * mean_weight;
127	    return std::max(0.0, variance);
128	}
