329	                long long w_next_p = estimated_weights[sorted_pivot_item_indices[insert_pos_arr_idx]];
330	                if (w_prev_p > 0 && w_next_p > 0) {
331	                    estimated_weights[i] = static_cast<long long>(std::sqrt(static_cast<double>(w_prev_p) * w_next_p));
332	                } else {
333	                    estimated_weights[i] = (w_prev_p + w_next_p) / 2;
334	                }
335	                estimated_weights[i] = std::max(w_prev_p, estimated_weights[i]);
336	                estimated_weights[i] = std::min(w_next_p, estimated_weights[i]);
337	            }
338	            if (estimated_weights[i] <= 0) estimated_weights[i] = 1;
339	        }
340	    }
341	
342	    for (int i = 0; i < N_items_global; ++i) {
343	        if (estimated_weights[i] <= 0) estimated_weights[i] = BASE_WEIGHT;
344	    }
345	
346	    // --- Partitioning Phase: LPT greedy + SA ---
347	    std::vector<int> assignment_array(N_items_global);
348	    std::vector<long long> group_sums_array(D_groups_global, 0);
349	    long long total_sum_est_val = 0;
350	    std::vector<std::vector<int>> group_items_indices(D_groups_global);
351	    std::vector<int> item_pos_in_group_vector(N_items_global);
352	
353	    std::vector<std::pair<long long, int>> items_sorted_for_greedy(N_items_global);
354	    for (int i = 0; i < N_items_global; ++i) {
355	        items_sorted_for_greedy[i] = {-estimated_weights[i], i};
356	        total_sum_est_val += estimated_weights[i];
357	    }
358	    std::sort(items_sorted_for_greedy.begin(), items_sorted_for_greedy.end());
359	
360	    for (int i = 0; i < N_items_global; ++i) {
361	        int item_idx = items_sorted_for_greedy[i].second;
362	        long long item_w = estimated_weights[item_idx];
363	        int best_grp = 0;
364	        long long min_sum = group_sums_array[0];
365	        for (int j = 1; j < D_groups_global; ++j) {
366	            if (group_sums_array[j] < min_sum) {
367	                min_sum = group_sums_array[j];
368	                best_grp = j;
369	            }
370	        }
371	        assignment_array[item_idx] = best_grp;
372	        group_sums_array[best_grp] += item_w;
373	        group_items_indices[best_grp].push_back(item_idx);
374	        item_pos_in_group_vector[item_idx] = group_items_indices[best_grp].size() - 1;
375	    }
376	
377	    double current_sum_sq_group_totals = 0;
378	    for (long long s : group_sums_array) {
379	        current_sum_sq_group_totals += static_cast<double>(s) * s;
380	    }
381	    double current_var = calculate_variance_from_sums(current_sum_sq_group_totals, static_cast<double>(total_sum_est_val), D_groups_global);
382	
383	    // SA on estimated weights
384	    double T = std::max(1.0, current_var * 0.25);
385	    if (current_var < 1e-9 && total_sum_est_val > 0) {
386	        T = std::max(1.0, static_cast<double>(total_sum_est_val) / std::max(1, N_items_global) * 0.1);
387	    }
388	    if (D_groups_global <= 1) T = 0;
389	
390	    std::uniform_real_distribution<double> unif_dist(0.0, 1.0);
391	    int sa_iters_count = 0;
392	    int no_improvement_streak = 0;
393	    const int REHEAT_THRESH = N_items_global * 15;
394	    const int CHECK_TIME_INTERVAL = 256;
395	
396	    // Run SA - the refinement phase is very fast (just I/O) so give SA most of the time
397	    std::chrono::milliseconds sa_time_limit_ms(1750);
398	
399	    while (D_groups_global > 1 && N_items_global > 0) {
400	        sa_iters_count++;
401	        if (sa_iters_count % CHECK_TIME_INTERVAL == 0) {
402	            auto time_now = std::chrono::steady_clock::now();
403	            if (std::chrono::duration_cast<std::chrono::milliseconds>(time_now - program_start_time) >= sa_time_limit_ms) break;
404	            T *= 0.9999;
405	            if (no_improvement_streak > REHEAT_THRESH && T < current_var * 0.05 && current_var > 1.0) {
406	                T = std::max(1.0, current_var * 0.125);
407	                no_improvement_streak = 0;
408	            }
409	        }
410	        if (T < 1e-12 && current_var > 1e-9) T = 1e-9;
411	        if (T < 1e-12 && current_var < 1.0 + 1e-9) break;
412	
413	        bool try_swap = (rng_engine() % 3 == 0);
