                group_items_indices[grp2].push_back(item1);
                item_pos_in_group_vector[item1] = group_items_indices[grp2].size() - 1;
                group_items_indices[grp1].push_back(item2);
                item_pos_in_group_vector[item2] = group_items_indices[grp1].size() - 1;

